// ── Produce basket widget — real photo, decay shown via state filter ─────────
const BASKET_IMG = "data:image/png;base64,";
function FreshBasket({ freshness, onClick }) {
  const s = FRESH_STATES[freshness];
  const exclaim = {
    fresh:  null,
    week1:  { dim: 22, fs: 13, color: "#D4A017", anim: false },
    week3:  { dim: 26, fs: 15, color: "#D4600A", anim: true  },
    month1: { dim: 31, fs: 19, color: "#C0392B", anim: true  },
  }[freshness];
  return (
    <div
      onClick={onClick}
      style={{ position: "relative", width: 146, height: 92, cursor: "pointer", flexShrink: 0 }}
    >
      {/* Urgency badge — circular pill, top-right corner */}
      {exclaim && (
        <div style={{
          position: "absolute", top: -4, right: -2, zIndex: 40,
          width: exclaim.dim, height: exclaim.dim, borderRadius: "50%",
          background: exclaim.color, color: "white",
          display: "flex", alignItems: "center", justifyContent: "center",
          fontWeight: 900, fontSize: exclaim.fs, lineHeight: 1,
          border: "2px solid #fff",
          boxShadow: "0 2px 7px rgba(0,0,0,0.4)",
          animation: exclaim.anim ? "badgePop 1.2s ease-in-out infinite" : "none",
          userSelect: "none",
        }}>!</div>
      )}
      <img
        src={BASKET_IMG}
        alt="Your produce basket"
        draggable={false}
        style={{
          width: "100%", height: "100%", objectFit: "contain", display: "block",
          filter: s.filter,
          transition: "filter 0.4s ease",
          pointerEvents: "none",
        }}
      />
    </div>
  );
}

