  // ── Chat state ────────────────────────────────────────────────────────────
  // Each entry: { from: 'bot'|'user', text: string }
  const [messages,   setMessages]   = useState([]);
  const [nodeKey,    setNodeKey]    = useState("intro");
  const [typing,     setTyping]     = useState(false);
  const [showReplies, setShowReplies] = useState(false);
  const scrollRef = useRef(null);
  // Seed the first bot message when chat opens
  useEffect(() => {
    if (screen === "chat" && messages.length === 0) {
      deliverBotNode("intro", []);
    }
  }, [screen]);
  // Auto-scroll to bottom
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, typing, showReplies]);
  function deliverBotNode(key, currentMessages) {
    const node = TREE[key];
    setNodeKey(key);
    setShowReplies(false);
    setTyping(true);
    // Deliver each line sequentially with a small delay
    const lines = node.lines;
    let delay = 700;
    const newMsgs = [...currentMessages];
    lines.forEach((line, i) => {
      setTimeout(() => {
        newMsgs.push({ from: "bot", text: line });
        setMessages([...newMsgs]);
        if (i === lines.length - 1) {
          setTyping(false);
          setTimeout(() => setShowReplies(true), 300);
        }
      }, delay * (i + 1));
    });
  }
  function handleReply(reply) {
    setShowReplies(false);
    const updated = [...messages, { from: "user", text: reply.text }];
    setMessages(updated);
    setTimeout(() => deliverBotNode(reply.next, updated), 600);
  }
